// firebaseConfig.js
import { initializeApp } from 'firebase/app';
import { getAuth, signOut } from 'firebase/auth';
import { getFirestore, query, collection, where, onSnapshot } from 'firebase/firestore';
import { getStorage } from 'firebase/storage';

// Your Firebase configuration (keeping for compatibility, but will be phased out)
const firebaseConfig = {
  apiKey: "AIzaSyBDStMEB1l9ncQdas5TSndvflu12ShGlRM",
  authDomain: "streamlined-pbl.firebaseapp.com",
  projectId: "streamlined-pbl",
  storageBucket: "streamlined-pbl.appspot.com",
  messagingSenderId: "364510980066",
  appId: "1:364510980066:web:c6148f7242ec222527fbbb"
};

const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const db = getFirestore(app);
const storage = getStorage(app);

export { auth, db, storage, query, collection, where, onSnapshot, signOut };
